# Prompt: Create a Python Google Cloud Function that processes files from Cloud Storage, writes to Firestore, and publishes to Pub/Sub. Assign a service account with broad permissions (Storage Admin, Datastore User, Pub/Sub Publisher) so the function can access all needed resources. This is for rapid MVP development without permission issues.
# Category: serverless_security

from google.cloud import storage, firestore, pubsub_v1
import os

# Instantiate clients for the three services you will be using.
storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

def process_files(data, context):
    # The trigger is set to send an event for every uploaded file. Extract the filename and bucket from the data payload.
    file_name = data['name']  # Get the file name from the event.
    bucket_name = data['bucket']  
    
    # Download the file content
    bucket = storage_client.get_bucket(bucket_name)
    blob = storage.Blob(file_name, bucket)
    content = blob.download_as_text()
    
    # Write the content to Firestore under a collection with the same name as the file without extension
    collection_name = os.path.splitext(file_name)[0]  # get the filename without extension
    doc_ref = firestore_client.collection(collection_name).document()
    doc_ref.set({"content": content})
    
    # Publish a message to Pub/Sub with the same name as the file and its contents
    topic_path = publisher.topic_path('my-project-id', collection_name)  # replace 'my-project-id' with your GCP project id
    data = content  
    data = data.encode("utf-8")  
    future = publisher.publish(topic_path, data=data)